import { useCallback, useEffect, useSyncExternalStore } from "react";

import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:custom-theme";

let listeners: Array<() => void> = [];
let lastThemeId: string | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  return raw ?? "t3-dark";
}

function applyThemeCssVars(theme: Theme, suppressTransitions = false): void {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const { colors, colorScheme, fontFamily, fontSize } = theme;
  const root = document.documentElement;
  const isDark = colorScheme === "dark";

  root.style.setProperty("color-scheme", colorScheme);
  root.style.setProperty("--background", colors.background);
  root.style.setProperty("--foreground", colors.foreground);
  root.style.setProperty("--card", colors.sidebar);
  root.style.setProperty("--card-foreground", colors.foreground);
  root.style.setProperty("--popover", colors.background);
  root.style.setProperty("--popover-foreground", colors.foreground);
  root.style.setProperty("--primary", colors.accent);
  root.style.setProperty("--primary-foreground", "#ffffff");
  root.style.setProperty(
    "--secondary",
    isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)",
  );
  root.style.setProperty("--secondary-foreground", colors.foreground);
  root.style.setProperty(
    "--muted",
    isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)",
  );
  root.style.setProperty(
    "--muted-foreground",
    `color-mix(in srgb, ${colors.foreground} 55%, ${colors.background})`,
  );
  root.style.setProperty(
    "--accent",
    isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.04)",
  );
  root.style.setProperty("--accent-foreground", colors.foreground);
  root.style.setProperty(
    "--border",
    isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.08)",
  );
  root.style.setProperty(
    "--input",
    isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.10)",
  );
  root.style.setProperty("--ring", colors.accent);
  root.style.setProperty("--t3-sidebar-bg", colors.sidebar);
  root.style.setProperty("--t3-editor-bg", colors.editor);
  root.style.setProperty("--t3-terminal-bg", colors.terminal);
  root.style.setProperty("--t3-status-bar-bg", colors.statusBar);
  root.style.setProperty("--t3-font-family", fontFamily);
  root.style.setProperty("--t3-font-size", `${fontSize}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyThemeCssVars(getTheme(getStoredThemeId()));

function getSnapshot(): string {
  const id = getStoredThemeId();
  if (lastThemeId !== null && lastThemeId === id) return lastThemeId;
  lastThemeId = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      applyThemeCssVars(getTheme(getStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useCustomTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(themeId);
  const availableThemes = listThemes();

  const setTheme = useCallback((id: string): void => {
    localStorage.setItem(STORAGE_KEY, id);
    applyThemeCssVars(getTheme(id), true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyThemeCssVars(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes } as const;
}

